import numpy as nplx=1 ##length along x directionly=1.5 ##length along y directionnx=21 ##no of divisions in x directionny=21 ##no of divisions in y directiondx=lx/(nx-1)dy=ly/(ny-1)x = np.zeros((nx, ny))#defining the array for x directiony = np.zeros((nx, ny))#defining the array for the y directiona_w=1/(dx*dx)a_e=1/(dx*dx)a_s=1/(dy*dy)a_n=1/(dy*dy)a_p=-2*(a_w + a_s)##for grid generationfor i in range(nx):    for j in range(ny):        x[i][j]=i*dx        y[i][j]=j*dy        ##for initialization of interior nodesT_old=np.zeros((nx,ny))#for i in range(1,nx-1):    #for j in range(1,ny-1):        #T_old[i][j]=0        #iterationsres=1.0count=1final=(10)**(-6)while res>=final:    T_new=np.zeros((nx,ny))    sum1=0    #top boundary condition    for i in range(nx):        T_old[i][ny-1]=100.0            #bottom boundary condition    for i in range(nx):        T_old[i][0]=0.0            #left boundary condition    for j in range(1,ny-1):        T_old[0][j]=0.0            #right boundary condition    for j in range(1,ny-1):        T_old[nx-1][j]=0.0            #point jacobi iteration updation algorithm    for i in range(1,nx-1):        for j in range(1,ny-1):            T_new[i][j]=-(a_s*T_old[i][j-1] + a_w*T_old[i-1][j] + a_e*T_old[i+1][j] + a_n*T_old[i][j+1] )/a_p            sum1=sum1+abs(T_new[i][j] - T_old[i][j])    #for point jacobi we are storing the entire array of t_new to the entire array of t_old            for i in range(1,nx-1):        for j in range(1,ny-1):            T_old[i][j]=T_new[i][j]                res=sum1    count=count + 1#displaying the values of temperature at each and every node after the iterations are completedprint(f"{'x':<20}{'y':<20}{'T_old':<25}{'T_new':<25}")for i in range(nx):    for j in range(ny):        print(f"{x[i][j]:<20}{y[i][j]:<20}{T_old[i][j]:<25}{T_new[i][j]:<25}")        